    for (all_models) |gm| {
        var m = gm.model;
        if (gm.compat_json) |json| {
            const parsed = std.json.parseFromSlice(std.json.Value, std.heap.page_allocator, json, .{}) catch null;
            if (parsed) |p| { m.compat = p.value; }
        }
        models_mod.registerModel(m);
    }
}
